def valid_parentheses(s):
    """
    Check if parentheses are balanced.
    O(n) time, O(n) space.
    """
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}

    for char in s:
        if char in mapping:
            if not stack or stack.pop() != mapping[char]:
                return False
        else:
            stack.append(char)

    return len(stack) == 0


def evaluate_rpn(tokens):
    """
    Evaluate Reverse Polish Notation.
    O(n) time, O(n) space.
    """
    stack = []
    operators = {
        "+": lambda a, b: a + b,
        "-": lambda a, b: a - b,
        "*": lambda a, b: a * b,
        "/": lambda a, b: int(a / b)  # Truncate toward zero
    }

    for token in tokens:
        if token in operators:
            b, a = stack.pop(), stack.pop()
            stack.append(operators[token](a, b))
        else:
            stack.append(int(token))

    return stack[0]


def daily_temperatures(temperatures):
    """
    Find days until warmer temperature.
    Monotonic decreasing stack approach.
    O(n) time, O(n) space.
    """
    n = len(temperatures)
    result = [0] * n
    stack = []  # Stack of indices

    for i in range(n):
        # Pop while current temp is warmer
        while stack and temperatures[i] > temperatures[stack[-1]]:
            prev_index = stack.pop()
            result[prev_index] = i - prev_index

        stack.append(i)

    return result


def sliding_window_maximum(nums, k):
    """
    Maximum in each sliding window of size k.
    Monotonic decreasing deque approach.
    O(n) time, O(k) space.
    """
    from collections import deque

    result = []
    dq = deque()  # Store indices

    for i in range(len(nums)):
        # Remove indices outside window
        while dq and dq[0] < i - k + 1:
            dq.popleft()

        # Remove smaller elements
        while dq and nums[dq[-1]] < nums[i]:
            dq.pop()

        dq.append(i)

        # Window is complete
        if i >= k - 1:
            result.append(nums[dq[0]])

    return result

class TreeNode:
    """Binary tree node"""
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right


class BinarySearchTree:
    """
    Binary Search Tree with all standard operations.

    BST Property: For each node N:
    - All values in left subtree < N.val
    - All values in right subtree > N.val

    Average case: O(log n) for all operations
    Worst case (unbalanced): O(n)
    """

    def __init__(self):
        self.root = None

    def insert(self, val):
        """Insert value maintaining BST property"""
        self.root = self._insert_recursive(self.root, val)

    def _insert_recursive(self, node, val):
        if not node:
            return TreeNode(val)

        if val < node.val:
            node.left = self._insert_recursive(node.left, val)
        elif val > node.val:
            node.right = self._insert_recursive(node.right, val)
        # Duplicate values not inserted

        return node

    def search(self, val):
        """Search for value - O(log n) average"""
        return self._search_recursive(self.root, val)

    def _search_recursive(self, node, val):
        if not node:
            return None

        if val == node.val:
            return node
        elif val < node.val:
            return self._search_recursive(node.left, val)
        else:
            return self._search_recursive(node.right, val)

    def delete(self, val):
        """Delete value from BST"""
        self.root = self._delete_recursive(self.root, val)

    def _delete_recursive(self, node, val):
        if not node:
            return None

        if val < node.val:
            node.left = self._delete_recursive(node.left, val)
        elif val > node.val:
            node.right = self._delete_recursive(node.right, val)
        else:
            # Node to delete found

            # Case 1: Leaf node
            if not node.left and not node.right:
                return None

            # Case 2: One child
            if not node.left:
                return node.right
            if not node.right:
                return node.left

            # Case 3: Two children
            # Find inorder successor (smallest in right subtree)
            successor = self._find_min(node.right)
            node.val = successor.val
            node.right = self._delete_recursive(node.right, successor.val)

        return node

    def _find_min(self, node):
        """Find minimum value node"""
        while node.left:
            node = node.left
        return node

    def _find_max(self, node):
        """Find maximum value node"""
        while node.right:
            node = node.right
        return node


# Tree Traversals

def inorder_traversal(root):
    """Left -> Root -> Right (gives sorted order for BST)"""
    result = []

    def inorder(node):
        if node:
            inorder(node.left)
            result.append(node.val)
            inorder(node.right)

    inorder(root)
    return result


def preorder_traversal(root):
    """Root -> Left -> Right"""
    result = []

    def preorder(node):
        if node:
            result.append(node.val)
            preorder(node.left)
            preorder(node.right)

    preorder(root)
    return result


def postorder_traversal(root):
    """Left -> Right -> Root"""
    result = []

    def postorder(node):
        if node:
            postorder(node.left)
            postorder(node.right)
            result.append(node.val)

    postorder(root)
    return result


def level_order_traversal(root):
    """BFS - Level by level"""
    if not root:
        return []

    from collections import deque

    result = []
    queue = deque([root])

    while queue:
        level = []
        level_size = len(queue)

        for _ in range(level_size):
            node = queue.popleft()
            level.append(node.val)

            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)

        result.append(level)

    return result


