def is_valid_bst(root):
    """
    Validate BST property.
    O(n) time, O(h) space.
    """
    def validate(node, min_val, max_val):
        if not node:
            return True

        if node.val <= min_val or node.val >= max_val:
            return False

        return (validate(node.left, min_val, node.val) and
                validate(node.right, node.val, max_val))

    return validate(root, float("-inf"), float("inf"))


def max_depth(root):
    """Tree height/maximum depth"""
    if not root:
        return 0
    return 1 + max(max_depth(root.left), max_depth(root.right))


def is_balanced(root):
    """
    Check if tree is height-balanced.
    A tree is balanced if heights of subtrees differ by at most 1.
    """
    def check(node):
        if not node:
            return 0

        left = check(node.left)
        right = check(node.right)

        if left == -1 or right == -1 or abs(left - right) > 1:
            return -1

        return 1 + max(left, right)

    return check(root) != -1


def lowest_common_ancestor(root, p, q):
    """
    Find LCA of two nodes in BST.
    O(log n) average using BST property.
    """
    while root:
        if p.val < root.val and q.val < root.val:
            root = root.left
        elif p.val > root.val and q.val > root.val:
            root = root.right
        else:
            return root

    return None

class HashTable:
    """
    Hash Table with chaining for collision resolution.

    Average case: O(1) for all operations
    Worst case: O(n) when many collisions

    Load factor α = n/m (items/buckets)
    Keep α < 0.75 for good performance
    """

    def __init__(self, initial_capacity=16):
        self.capacity = initial_capacity
        self.size = 0
        self.buckets = [[] for _ in range(self.capacity)]
        self.LOAD_FACTOR_THRESHOLD = 0.75

    def _hash(self, key):
        """Hash function - maps key to bucket index"""
        return hash(key) % self.capacity

    def _resize(self):
        """Double capacity and rehash all items"""
        old_buckets = self.buckets
        self.capacity *= 2
        self.buckets = [[] for _ in range(self.capacity)]
        self.size = 0

        for bucket in old_buckets:
            for key, value in bucket:
                self.put(key, value)

    def put(self, key, value):
        """Insert or update key-value pair"""
        # Check load factor
        if self.size / self.capacity >= self.LOAD_FACTOR_THRESHOLD:
            self._resize()

        index = self._hash(key)
        bucket = self.buckets[index]

        # Update if key exists
        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)
                return

        # Insert new key
        bucket.append((key, value))
        self.size += 1

    def get(self, key, default=None):
        """Retrieve value by key"""
        index = self._hash(key)
        bucket = self.buckets[index]

        for k, v in bucket:
            if k == key:
                return v

        return default

    def remove(self, key):
        """Remove key-value pair"""
        index = self._hash(key)
        bucket = self.buckets[index]

        for i, (k, v) in enumerate(bucket):
            if k == key:
                del bucket[i]
                self.size -= 1
                return v

        raise KeyError(key)

    def __contains__(self, key):
        """Check if key exists"""
        index = self._hash(key)
        bucket = self.buckets[index]
        return any(k == key for k, v in bucket)

    def __len__(self):
        return self.size

    def keys(self):
        """Return all keys"""
        for bucket in self.buckets:
            for k, v in bucket:
                yield k

    def values(self):
        """Return all values"""
        for bucket in self.buckets:
            for k, v in bucket:
                yield v

    def items(self):
        """Return all key-value pairs"""
        for bucket in self.buckets:
            for item in bucket:
                yield item


class HashTableOpenAddressing:
    """
    Hash Table with open addressing (linear probing).
    """

    DELETED = object()  # Tombstone marker

    def __init__(self, initial_capacity=16):
        self.capacity = initial_capacity
        self.size = 0
        self.keys = [None] * self.capacity
        self.values = [None] * self.capacity

    def _hash(self, key):
        return hash(key) % self.capacity

    def _probe(self, key):
        """Linear probing - find slot for key"""
        index = self._hash(key)

        while self.keys[index] is not None:
            if self.keys[index] == key:
                return index
            if self.keys[index] is self.DELETED:
                # Can insert here
                return index

            index = (index + 1) % self.capacity

        return index

    def put(self, key, value):
        if self.size / self.capacity >= 0.5:
            self._resize()

        index = self._probe(key)

        if self.keys[index] is None or self.keys[index] is self.DELETED:
            self.size += 1

        self.keys[index] = key
        self.values[index] = value

    def get(self, key, default=None):
        index = self._hash(key)

        while self.keys[index] is not None:
            if self.keys[index] == key:
                return self.values[index]
            index = (index + 1) % self.capacity

        return default

    def remove(self, key):
        index = self._hash(key)

        while self.keys[index] is not None:
            if self.keys[index] == key:
                value = self.values[index]
                self.keys[index] = self.DELETED
                self.values[index] = None
                self.size -= 1
                return value
            index = (index + 1) % self.capacity

        raise KeyError(key)

    def _resize(self):
        old_keys = self.keys
        old_values = self.values

        self.capacity *= 2
        self.keys = [None] * self.capacity
        self.values = [None] * self.capacity
        self.size = 0

        for i, key in enumerate(old_keys):
            if key is not None and key is not self.DELETED:
                self.put(key, old_values[i])


# Hash Table Applications

def two_sum_hash(nums, target):
    """O(n) using hash table"""
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i
    return []


def group_anagrams(strs):
    """Group strings that are anagrams"""
    from collections import defaultdict

    groups = defaultdict(list)

    for s in strs:
        # Use sorted string as key
        key = tuple(sorted(s))
        groups[key].append(s)

    return list(groups.values())


def longest_consecutive_sequence(nums):
    """
    Find longest consecutive sequence.
    O(n) using hash set.
    """
    num_set = set(nums)
    longest = 0

    for num in num_set:
        # Only start counting from sequence start
        if num - 1 not in num_set:
            current_num = num
            current_length = 1

            while current_num + 1 in num_set:
                current_num += 1
                current_length += 1

            longest = max(longest, current_length)

    return longest


def subarray_sum_equals_k(nums, k):
    """
    Count subarrays with sum = k.
    O(n) using prefix sum + hash map.
    """
    from collections import defaultdict

    count = 0
    prefix_sum = 0
    sum_count = defaultdict(int)
    sum_count[0] = 1  # Empty prefix

    for num in nums:
        prefix_sum += num

        # Check if (prefix_sum - k) exists
        count += sum_count[prefix_sum - k]

        sum_count[prefix_sum] += 1

    return count

